#include <iostream>
#include <vector>
using namespace std;
struct gui
{
    vector<int> a;
    vector<int> num;
    int count;
};
gui b[100005];
int main()
{
    int n,q;
    cin>>n>>q;
    for(int i=0;i<=q-1;i++)
    {
        int c,x,y,z;
        cin>>c;
        if(c==1)
        {
            cin>>x>>y>>z;
            b[x].a.push_back(z);
            b[x].num.push_back(y);
            b[x].count++;
        }
        else
        {
            cin>>x>>y;
            for(int j=b[x].count-1;j>=0;j--)
            {
                if(b[x].num[j]==y)
                {
                    cout<<b[x].a[j]<<endl;
                    break;
                }
            }
        }
    }
    return 0;
}
